<template>
  <Form v-slot="{ meta }" :validation-schema="schema" @submit="handleSubmit">
    <div class="form form--article">
      <div class="form__group">
        <label class="form__label" for="title">Título</label>
        <Field
          v-model="form.title"
          name="title"
          type="text"
          class="form__control"
        />
        <ErrorMessage name="title" />
      </div>

      <div class="form__group">
        <label class="form__label" for="header">Cabecera / Bajada</label>
        <Field
          v-model="form.header"
          as="textarea"
          name="header"
          class="form__control"
          rows="3"
        />
        <ErrorMessage name="header" />
      </div>

      <div class="form__group">
        <label class="form__label">Cuerpo</label>
        <TextareaArticle v-model="form.body" />
      </div>

      <div class="form__group form__group--upload">
        <label class="form__label">Imagen de portada</label>
        <UploadMedia
          v-model="form.cover"
          :max-files="1"
          hint="Imagen principal del artículo (1 imagen)"
        />
      </div>

      <div class="form__group form__group--upload">
        <label class="form__label">Galería</label>
        <UploadMedia
          v-model="form.gallery"
          :max-files="10"
          hint="Imágenes adicionales del artículo (máximo 10)"
        />
      </div>

      <div class="form__group">
        <label class="form__label" for="seo_title">Título SEO</label>
        <Field
          v-model="form.seo_title"
          name="seo_title"
          type="text"
          class="form__control"
        />
        <ErrorMessage name="seo_title" />
      </div>

      <div class="form__group">
        <label class="form__label" for="seo_description">Descripción SEO</label>
        <Field
          v-model="form.seo_description"
          as="textarea"
          name="seo_description"
          class="form__control"
          rows="3"
        />
        <ErrorMessage name="seo_description" />
      </div>

      <div class="form__group">
        <label class="form__label" for="source_url">URL de fuente</label>
        <Field
          v-model="form.source_url"
          name="source_url"
          type="url"
          class="form__control"
          placeholder="https://..."
        />
        <ErrorMessage name="source_url" />
      </div>

      <div class="form__send">
        <button
          :disabled="sending || !meta.valid"
          type="submit"
          class="btn btn--primary"
        >
          {{ submitLabel }}
        </button>
      </div>
    </div>
  </Form>
</template>

<script setup lang="ts">
import { ref, computed, watch } from "vue";
import { Field, Form, ErrorMessage } from "vee-validate";
import * as yup from "yup";
import { useRoute, useRouter } from "vue-router";

interface MediaItem {
  id?: number;
  url?: string;
  formats?: {
    thumbnail?: { url: string };
    small?: { url: string };
    medium?: { url: string };
  };
}

interface ArticleData {
  id?: number;
  documentId?: string;
  title?: string;
  header?: string;
  body?: string;
  seo_title?: string;
  seo_description?: string;
  source_url?: string | null;
  publishedAt?: string | null;
  cover?: MediaItem[];
  gallery?: MediaItem[];
}

const props = defineProps<{
  article?: ArticleData | null;
}>();

const emit = defineEmits<{
  (e: "saved", article: ArticleData): void;
}>();

const { Swal } = useSweetAlert2();
const router = useRouter();
const route = useRoute();
const apiClient = useApiClient();

const sending = ref(false);
const lastHydratedId = ref<string | number | null>(null);

const schema = yup.object({
  title: yup.string().required("Título es requerido"),
  header: yup.string().optional(),
  body: yup.string().optional(),
  seo_title: yup.string().optional(),
  seo_description: yup.string().optional(),
  source_url: yup.string().url("URL inválida").optional().nullable(),
});

const form = ref<{
  title: string;
  header: string;
  body: string;
  seo_title: string;
  seo_description: string;
  source_url: string;
  cover: MediaItem[];
  gallery: MediaItem[];
}>({
  title: "",
  header: "",
  body: "",
  seo_title: "",
  seo_description: "",
  source_url: "",
  cover: [],
  gallery: [],
});

const isEditMode = computed(() =>
  Boolean(props.article?.documentId || props.article?.id),
);

const submitLabel = computed(() =>
  isEditMode.value ? "Actualizar artículo" : "Crear artículo",
);

const hydrateForm = () => {
  form.value = {
    title: props.article?.title || "",
    header: props.article?.header || "",
    body: props.article?.body || "",
    seo_title: props.article?.seo_title || "",
    seo_description: props.article?.seo_description || "",
    source_url: props.article?.source_url || "",
    cover: props.article?.cover || [],
    gallery: props.article?.gallery || [],
  };
  lastHydratedId.value = props.article?.id || props.article?.documentId || null;
};

const handleSubmit = async (values: Record<string, unknown>) => {
  sending.value = true;

  try {
    const coverIds = form.value.cover
      .map((m) => m.id)
      .filter((id): id is number => id !== undefined);
    const galleryIds = form.value.gallery
      .map((m) => m.id)
      .filter((id): id is number => id !== undefined);

    const payload = {
      title: (values.title as string).trim(),
      header: (values.header as string)?.trim() || null,
      body: form.value.body?.trim() || null,
      seo_title: (values.seo_title as string)?.trim() || null,
      seo_description: (values.seo_description as string)?.trim() || null,
      source_url: form.value.source_url.trim() || null,
      cover: coverIds.length > 0 ? coverIds : null,
      gallery: galleryIds.length > 0 ? galleryIds : null,
    };

    if (isEditMode.value) {
      const routeId = route.params.id;
      const documentId =
        props.article?.documentId ||
        (typeof routeId === "string" ? routeId : undefined);

      if (!documentId) {
        await Swal.fire(
          "Error",
          "No se pudo identificar el artículo para actualizar.",
          "error",
        );
        sending.value = false;
        return;
      }

      const response = await apiClient<{
        data: { id?: number; documentId?: string };
      }>(`/articles/${documentId}`, { method: "PUT", body: { data: payload } });
      const responseData = response.data;
      const updatedArticle = {
        ...props.article,
        ...responseData,
        ...payload,
      };
      form.value = {
        title: payload.title,
        header: payload.header || "",
        body: payload.body || "",
        seo_title: payload.seo_title || "",
        seo_description: payload.seo_description || "",
        source_url: payload.source_url || "",
        cover: form.value.cover,
        gallery: form.value.gallery,
      };
      emit("saved", updatedArticle as ArticleData);
      await Swal.fire(
        "Éxito",
        "Artículo actualizado correctamente.",
        "success",
      );
      const updatedId = responseData?.documentId || responseData?.id;
      if (updatedId) {
        router.push(`/dashboard/articles/${updatedId}`);
      }
    } else {
      const response = await apiClient<{
        data: { id?: number; documentId?: string };
      }>("/articles?status=draft", {
        method: "POST",
        body: { data: payload },
      });
      const createdData = response.data;
      emit("saved", (createdData as ArticleData) || ({} as ArticleData));
      await Swal.fire("Éxito", "Artículo creado correctamente.", "success");
      const createdId = createdData?.documentId || createdData?.id;
      if (createdId) {
        router.push(`/dashboard/articles/${createdId}/edit`);
      } else {
        router.push("/dashboard/articles");
      }
    }
  } catch (error) {
    console.error("Error saving article:", error);
    await Swal.fire("Error", "No se pudo guardar el artículo.", "error");
  } finally {
    sending.value = false;
  }
};

watch(
  () => props.article,
  (value) => {
    if (!value || sending.value) return;
    const currentId = value.id || value.documentId || null;
    if (currentId && currentId === lastHydratedId.value) return;
    hydrateForm();
  },
  { immediate: true },
);
</script>
